class Solution:
    def inorderHeapify(self, nums) -> None:
        n = len(nums)
        for i in range(1, n):
            parent = (i - 1) >> 1
            while i > 0 and nums[parent] < nums[i]:
                nums[parent], nums[i] = nums[i], nums[parent]
                i = parent
                parent = (i - 1) >> 1

